برای ساخت یک فرم ثبت‌نام ساده، ابتدا با HTML فرم رو ایجاد می‌کنیم. به طور مثال:

<form id="signupForm">
  <input type="text" id="username" placeholder="نام کاربری">
  <input type="email" id="email" placeholder="ایمیل">
  <input type="password" id="password" placeholder="رمز عبور">
  <button type="submit">ثبت‌نام</button>
</form>

در CSS فرم رو کمی استایل می‌دیم تا بهتر دیده بشه. حالا در JavaScript با استفاده از Event Listener فرم رو کنترل می‌کنیم و قبل از ارسال، اعتبارسنجی انجام می‌دیم:

const form = document.getElementById('signupForm');
form.addEventListener('submit', function(event) {
  event.preventDefault();
  const username = document.getElementById('username').value.trim();
  const email = document.getElementById('email').value.trim();
  const password = document.getElementById('password').value;

  if(username === '' || email === '' || password === '') {
    alert('لطفاً همه فیلدها را پر کنید.');
    return;
  }

  const emailRegex = /^[\w-\.]+@([\w-]+\.)+[\w-]{2,4}$/;
  if(!emailRegex.test(email)) {
    alert('ایمیل وارد شده معتبر نیست.');
    return;
  }

  if(password.length < 6) {
    alert('رمز عبور باید حداقل ۶ کاراکتر باشد.');
    return;
  }

  alert('ثبت‌نام با موفقیت انجام شد!');
});

این نمونه ساده به شما کمک می‌کنه فرم‌هایی با اعتبارسنجی پایه بسازید.
